import{_ as o,o as t,c as d,a2 as c}from"./chunks/framework.BKG_UbFK.js";const p=JSON.parse('{"title":"Architecture","description":"","frontmatter":{},"headers":[],"relativePath":"en/guide/architecture.md","filePath":"en/guide/architecture.md"}'),r={name:"en/guide/architecture.md"};function a(s,e,i,l,n,u){return t(),d("div",null,[...e[0]||(e[0]=[c('<h1 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h1><h2 id="how-resolution-works" tabindex="-1">How resolution works <a class="header-anchor" href="#how-resolution-works" aria-label="Permalink to &quot;How resolution works&quot;">​</a></h2><p><code>resolveFor()</code> is the core of Clearance&#39;s contextual authorization - see <a href="/clearance-docs/en/features/contextual-authorization.html">Contextual Authorization</a> for the full API. It merges three sources, in this precedence order:</p><ol><li><strong>Contextual role grants</strong> - permissions from roles the user holds specifically within this context (<code>clr_role_ctx</code>).</li><li><strong>Global role grants</strong> - permissions from the user&#39;s globally-assigned Spatie roles (so <code>super_admin</code> and other global roles satisfy <code>canIn()</code> for any context).</li><li><strong>Per-context overrides</strong> (<code>clr_ctx_overrides</code>) - <code>forced_on</code> adds a permission on top of the above; <code>forced_off</code> removes it, even if the permission was granted by a global role. A deny always wins.</li></ol><div class="warning custom-block"><p class="custom-block-title">A deny always wins</p><p><code>forced_off</code> overrides any permission granted by a global role or a contextual role grant. There is no way to &quot;out-rank&quot; a <code>forced_off</code> override for the same user/permission/context short of removing it.</p></div><h2 id="database" tabindex="-1">Database <a class="header-anchor" href="#database" aria-label="Permalink to &quot;Database&quot;">​</a></h2><p>Clearance owns 6 tables and never alters Spatie&#39;s core tables (<code>roles</code>, <code>permissions</code>, <code>model_has_roles</code>, <code>model_has_permissions</code>, <code>role_has_permissions</code>). All FKs referencing <code>roles.id</code>/<code>permissions.id</code> cascade on delete unless noted; Spatie tables have no FKs pointing back to <code>clr_*</code>.</p><table tabindex="0"><thead><tr><th>Table</th><th>Key columns</th></tr></thead><tbody><tr><td><code>clr_meta</code></td><td><code>subject_type</code>, <code>subject_key</code> (unique together) - <code>display_name</code>, <code>description</code>, <code>icon_svg</code>, <code>color</code> - display metadata for a role or guard</td></tr><tr><td><code>clr_role_meta</code></td><td><code>role_id</code> (unique, FK -&gt; <code>roles</code>) - <code>is_locked</code>, <code>scope</code> (<code>global</code>|<code>contextual</code>), <code>context_types</code> (json) - <code>parent_role_id</code> (nullable FK -&gt; <code>roles</code>, <code>ON DELETE SET NULL</code>) - ceiling role</td></tr><tr><td><code>clr_guards</code></td><td><code>name</code> (unique), <code>driver</code>, <code>provider</code> - guards managed via the panel</td></tr><tr><td><code>clr_settings</code></td><td><code>key</code> (unique), <code>value</code> - runtime key/value store (default role, etc.)</td></tr><tr><td><code>clr_role_ctx</code></td><td><code>user_id</code>, <code>role_id</code> (FK -&gt; <code>roles</code>), <code>context_type</code>, <code>context_id</code> - contextual role assignments, unique per <code>(user, role, context_type, context_id)</code></td></tr><tr><td><code>clr_ctx_overrides</code></td><td><code>user_id</code>, <code>role_id</code> (FK -&gt; <code>roles</code>), <code>permission_id</code> (FK -&gt; <code>permissions</code>), <code>context_type</code>, <code>context_id</code>, <code>type</code> (<code>forced_on</code>|<code>forced_off</code>) - per-user, per-context permission overrides</td></tr></tbody></table><h2 id="never-touches-spatie-s-tables" tabindex="-1">Never touches Spatie&#39;s tables <a class="header-anchor" href="#never-touches-spatie-s-tables" aria-label="Permalink to &quot;Never touches Spatie&#39;s tables&quot;">​</a></h2><p>Clearance is designed to sit alongside <code>spatie/laravel-permission</code>, not replace it. Every <code>Role</code> and <code>Permission</code> record a Clearance panel creates or edits is a genuine Spatie model, stored in Spatie&#39;s own tables. Clearance never runs a migration that adds a column to, or writes an FK from, any of <code>roles</code>, <code>permissions</code>, <code>model_has_roles</code>, <code>model_has_permissions</code>, or <code>role_has_permissions</code>.</p><p>All of Clearance&#39;s own data - display metadata, role scope and ceilings, contextual assignments, per-context overrides, guard definitions, and settings - lives exclusively in the 6 <code>clr_*</code> tables above. This means:</p><ul><li>Uninstalling Clearance never risks corrupting your existing Spatie role/permission data.</li><li>Any code that already reads Spatie&#39;s models or tables directly keeps working unmodified.</li><li>Clearance&#39;s contextual and ceiling features are purely additive layers resolved at query time (via <code>resolveFor()</code> and <code>RoleService</code>), not baked into Spatie&#39;s schema.</li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="/clearance-docs/en/features/contextual-authorization.html">Contextual Authorization</a> - <code>canIn()</code>, <code>hasRoleIn()</code>, Blade directives, <code>ContextService</code></li><li><a href="/clearance-docs/en/features/roles.html">Roles</a> - scope and ceiling roles, <code>RoleService::setParent()</code></li><li><a href="/clearance-docs/en/guide/migration.html">Migration</a> - backfilling <code>clr_meta</code>/<code>clr_role_meta</code>/<code>clr_guards</code> onto an existing Spatie install</li><li><a href="/clearance-docs/en/guide/security.html">Security</a> - how the ceiling and override model prevents privilege escalation</li></ul>',14)])])}const _=o(r,[["render",a]]);export{p as __pageData,_ as default};
